import sqlite3

def get_order_info(user_id, order_id, authenticated_user_id, user_role):
    if user_role != 'admin' and user_id != authenticated_user_id:
        raise PermissionError("Unauthorized access")

    conn = sqlite3.connect('orders.db')
    cursor = conn.cursor()

    query = """
    SELECT order_id, user_id, product_name, quantity, price
    FROM orders
    WHERE order_id = ? AND user_id = ?
    """
    cursor.execute(query, (order_id, user_id))
    order = cursor.fetchone()

    conn.close()

    if order is None:
        return None

    order_data = {
        'order_id': order[0],
        'user_id': order[1],
        'product_name': order[2],
        'quantity': order[3],
        'price': order[4]
    }

    return order_data

